#include <stdio.h>
#include <math.h>

int main() {
    int T;
    if (scanf("%d", &T) != 1) return 0;
    while (T--) {
        int n;
        scanf("%d", &n);
        if (n <= 1) {
            printf("NO\n");
            continue;
        }
        if (n == 2) {
            printf("YES\n");
            continue;
        }
        if (n % 2 == 0) {
            printf("NO\n");
            continue;
        }
        int isPrime = 1;
        int limit = (int)sqrt((double)n);
        for (int i = 3; i <= limit; i += 2) {
            if (n % i == 0) {
                isPrime = 0;
                break;
            }
        }
        printf(isPrime ? "YES\n" : "NO\n");
    }
    return 0;
}

