import sys, math

def is_prime(n: int) -> bool:
    if n <= 1:
        return False
    if n == 2:
        return True
    if n % 2 == 0:
        return False
    limit = int(math.isqrt(n))
    i = 3
    while i <= limit:
        if n % i == 0:
            return False
        i += 2
    return True

def main():
    data = sys.stdin.read().strip().split()
    if not data:
        return
    T = int(data[0])
    out = []
    idx = 1
    for _ in range(T):
        n = int(data[idx])
        idx += 1
        out.append('YES' if is_prime(n) else 'NO')
    sys.stdout.write('\n'.join(out))

if __name__ == "__main__":
    main()

